"""Python bindings for the tank fill/drain controller."""

from pathlib import Path


def _load_controller_c():
    """Load the C controller module using coffi."""
    try:
        import coffi
    except ImportError:
        # Try to install coffi
        import subprocess
        subprocess.run(["pip3", "install", "koffi"], check=True, capture_output=True)
        import coffi

    # Load the C source file
    c_source = Path(__file__).parent / "controller.c"
    with open(c_source, "r") as f:
        source = f.read()

    # Parse and load the module
    return coffi.parse(source)


def _create_controller_object(module):
    """Create a controller object from the loaded C module."""
    # Get the struct definitions from the C file
    import re

    # Extract struct definitions
    struct_pattern = r'typedef struct \{([^}]+)\} (controller_t|controller_input_t|controller_output_t|controller_state_t)';

    structs = {}
    for match in re.finditer(struct_pattern, source):
        name = match.group(2)
        fields_str = match.group(1)
        # Convert C struct to Python dict
        fields = []
        for line in fields_str.strip().split('\n'):
            line = line.strip()
            if not line:
                continue
            parts = line.split(',')
            field_name = parts[0].strip()
            field_type = parts[1].strip() if len(parts) > 1 else "int"
            fields.append((field_name, field_type))
        structs[name] = dict(fields)

    return module


def _get_controller_struct(module):
    """Get the controller_t struct from the loaded C module."""
    import coffi

    # Get all members of controller_t
    controller_t = None
    for member in dir(module):
        if not member.startswith('_') and member == 'controller_t':
            controller_t = getattr(module, member)
            break

    if controller_t is None:
        return {}

    return {name: value for name, value in controller_t.__members__.items()}


# Load the C module
_controller_module = _load_controller_c()

