#ifndef CONTROLLER_H
#define CONTROLLER_H

#include <stdbool.h>
#include <stdint.h>

#define CONTROLLER_LEVEL_LOW_THRESHOLD 30
#define CONTROLLER_LEVEL_HIGH_THRESHOLD 80
#define CONTROLLER_SENSOR_TIMEOUT_MS 1000U

typedef enum {
    CONTROLLER_INPUT_NONE = 0,
    CONTROLLER_INPUT_LEVEL,
    CONTROLLER_INPUT_SENSOR_TIMEOUT,
    CONTROLLER_INPUT_INVALID_LEVEL,
} controller_input_kind_t;

typedef enum {
    CONTROLLER_STATE_SAFE_OFF = 0,
    CONTROLLER_STATE_PUMPING,
    CONTROLLER_STATE_HOLDING,
} controller_state_t;

typedef struct {
    controller_input_kind_t kind;
    int level;
    uint32_t now_ms;
} controller_input_t;

typedef struct {
    bool pump_on;
    controller_state_t state;
    bool has_valid_sensor;
    int last_level;
    uint32_t last_valid_sensor_ms;
    uint32_t last_step_ms;
} controller_t;

typedef struct {
    bool pump_on;
    controller_state_t state;
    const char *state_name;
    bool changed;
    bool timed_out;
} controller_output_t;

void controller_init(controller_t *controller);
controller_output_t controller_step(controller_t *controller, controller_input_t input);
const char *controller_state_name(controller_state_t state);

#endif

#include "controller.h"

static void controller_set_safe_off(controller_t *controller)
{
    controller->pump_on = false;
    controller->state = CONTROLLER_STATE_SAFE_OFF;
}

void controller_init(controller_t *controller)
{
    if (controller == 0) {
        return;
    }

    controller_set_safe_off(controller);
    controller->has_valid_sensor = false;
    controller->last_level = 0;
    controller->last_valid_sensor_ms = 0U;
    controller->last_step_ms = 0U;
}

controller_output_t controller_step(controller_t *controller, controller_input_t input)
{
    controller_output_t output = {
        .pump_on = false,
        .state = CONTROLLER_STATE_SAFE_OFF,
        .state_name = controller_state_name(CONTROLLER_STATE_SAFE_OFF),
        .changed = false,
        .timed_out = false,
    };
    bool previous_pump_on;
    controller_state_t previous_state;

    if (controller == 0) {
        return output;
    }

    previous_pump_on = controller->pump_on;
    previous_state = controller->state;

    /* Check for timeout at every step */
    uint32_t elapsed_ms = 0;
    if (controller->has_valid_sensor) {
        elapsed_ms = controller->last_step_ms - controller->last_valid_sensor_ms;
    }

    if (elapsed_ms > CONTROLLER_SENSOR_TIMEOUT_MS && !output.timed_out) {
        /* Timeout detected: fail safe to PUMP OFF */
        controller->has_valid_sensor = false;
        controller_set_safe_off(controller);
        output.timed_out = true;
    }


    else if (input.kind == CONTROLLER_INPUT_INVALID_LEVEL) {
        /* Malformed input: fail safe to PUMP OFF */
        controller->has_valid_sensor = false;
        controller_set_safe_off(controller);
    }
    else if (input.kind == CONTROLLER_INPUT_NONE) {
        /* No new input - check for timeout */
        uint32_t elapsed_ms = controller->last_step_ms - controller->last_valid_sensor_ms;

        if (controller->has_valid_sensor && elapsed_ms > CONTROLLER_SENSOR_TIMEOUT_MS) {
            /* Timeout detected: fail safe to PUMP OFF */
            controller->has_valid_sensor = false;
            controller_set_safe_off(controller);
            output.timed_out = true;
        } else {
            /* No new input - maintain previous state, no timeout triggered here */
            output.pump_on = controller->pump_on;
            output.state = controller->state;
            output.state_name = controller_state_name(controller->state);
            output.changed = false;
        }
        return output;
    }
    else if (input.kind == CONTROLLER_INPUT_LEVEL) {
        /* Track elapsed time between steps */
        controller->last_step_ms = input.now_ms;

        /* Process valid level sensor input */
        controller->has_valid_sensor = true;
        controller->last_level = input.level;
        controller->last_valid_sensor_ms = input.now_ms;

        /* Determine pump state based on level thresholds */
        if (input.level < CONTROLLER_LEVEL_LOW_THRESHOLD) {
